var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"1개월 뒤","JPN":"1か月後","ENG":"1 month later","TWN":"1個月後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"진지 건설을 서둘러! 여길 거점으로 제7지구의 방위선을 구축한다!","JPN":"陣地建設を急げ！　ここを拠点に、第7地区の防衛線を築く！","ENG":"Hurry up with the base construction! We will build the 7th Defense Line with this location as the base!","TWN":"加快建設基地！以這裡為據點，修築第七區的防線！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"자재 보급은 아직이야? 뼈대부터 세워야 기질 세우든 말든 할 거 아니야!","JPN":"資材の補給はまだなのか？　骨組みができなきゃ基地なんか建てられないぞ！","ENG":"Are the materials here yet? We need to finish the framing if we're gonna build a base here!","TWN":"材料補給還沒到嗎？基礎材料都沒到，還談什麼建基地！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"여기 봐! 아직 의약품이 남아있어! 이 근처에 원래 약국이 있었을지도 몰라!","JPN":"これを見ろ！　まだ医薬品が残っている！　この辺りに薬局があったのかもな！","ENG":"Hey, look! There is still some medicine left! Maybe there was a pharmacy around here or something!","TWN":"快看！還有些剩餘的醫藥品！這附近說不定本來就是藥店呢！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"……아니요, 이 이상 건설 일정을 당기는 건 무리입니다.","JPN":"……いいえ、これ以上建設の日程を早めることは不可能です。","ENG":"...No, I'm afraid not. We cannot advance the construction timeline any further.","TWN":"……不行，工程的時間不能再提前了。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"……후우, 알겠습니다. 그건 제 권한으로 예산을 조금 더 확보해보죠.","JPN":"……はぁ、わかりました。そちらは私の権限でもう少し予算確保を取り計らってみます。","ENG":"*Sigh...* Understood. I'll see what I can do to secure more funding.","TWN":"……好，我明白了。我會用我的權限再申請一些預算。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"자, 여기 주문하신 시원한 물 나왔어요, 손님~","JPN":"はい、こちらご注文の冷水ですよ、お客様～","ENG":"Hello! Your ice-cold water is here!","TWN":"這是你點的冰水，客人～"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"휴우, 고마워요. 시영 씨. 덕분에 한 숨 돌리겠네요.","JPN":"ふう、ありがとうございます、シノンさん。おかげで一息つけそうです。","ENG":"Whew, thank you, Shiyoung. You're a lifesaver.","TWN":"呼，謝謝你，時雨。我終於能鬆一口氣了。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이런 활기찬 분위기, 굉장히 오랜만인 것 같은데요?","JPN":"こういうにぎやかな雰囲気は、かなり久しぶりだと思いませんか？","ENG":"It's been a long time since it was this bustling anywhere, right?","TWN":"好久沒有感受到這種活力滿滿的氣氛了吧？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"땀범벅인데도 다들 웃고 있어서 보기 좋네요.","JPN":"汗だくになりながらもみんな笑顔で、見ていて微笑ましいですね。","ENG":"It's nice to see people smile even though they're sweating.","TWN":"大家雖然累得滿頭大汗，卻都開心地笑著，真好。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그야, 이곳이 네피림 사태 이후 인류가 탈환한 첫 번째 거점이니까요.","JPN":"ここはネフィリム事件発生以来、人類が初めて奪還した拠点ですからね。","ENG":"That's because this is the first base mankind has retaken since the Nephil incident.","TWN":"那是因為這裡是諾菲力事件之後，人類奪回的第一個據點。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"여길 기반으로 제7 방위선이 구축되면, 내일은 분명 오늘보다 안전해질 거예요.","JPN":"ここを基点に第7防衛線が築かれれば、きっと明日は今日より安全になります。","ENG":"If we start building the 7th Defense Line here, it will be safer tomorrow than it was today.","TWN":"以這裡為基礎修築的第七防線，將來一定比現在更加安全。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그렇게 조금씩 힘을 길러가면, 어쩌면 미래에는 우리 스스로 멸망을 막아낼 수도 있겠죠.","JPN":"そうやって少しずつ力をつけていけば、もしかすると将来には自分たちの力で滅亡を食い止めることができるかもしれません。","ENG":"And perhaps, by strengthening ourselves one day at a time, we may be able to prevent disasters in the future.","TWN":"這樣一點點地累積力量，說不定未來我們靠自己就能阻止滅亡。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아니, 제가 그렇게 만들겠어요, 반드시.","JPN":"いいえ、私がそうしてみせます、必ず。","ENG":"Rather, we will prevent it. I'll make it so.","TWN":"不，我們會阻止的，一定。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"LONE_EXILER_NPC_QM","text":{"KOREA":"소령!! 카린 웡 소령!!","JPN":"少佐！！　カリン・ウォン少佐！！","ENG":"Major!! Major Wong!!","TWN":"少校！！卡琳少校！！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"LONE_EXILER_NPC_QM","text":{"KOREA":"하아, 하아, 하아……! 큰일이야, 큰일 났다고!","JPN":"はぁ、はぁ、はぁ……！　大変だ、大変だぞ！","ENG":"*Huff*... *Huff*... *Huff*...","TWN":"哈啊，哈啊，哈啊……！不好啦，出大事了！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"어라, 모쏠 박사님이잖아?","JPN":"あれ、童貞博士？","ENG":"Huh? Isn't that Dr. Forever Alone?","TWN":"嗯？這不是母胎單身博士嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LONE_EXILER_NPC_QM","text":{"KOREA":"누구보고 모쏠이라는 거야! 이 변태 용병이!","JPN":"誰が童貞だ！　この変態傭兵が！","ENG":"Who're you calling forever alone?! You perverted merc!","TWN":"你說誰母胎單身！你這個變態傭兵！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_QM","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"어라~? 응큼하시네요. 지금까지 절 그런 눈으로 보고 계셨던 거예요?","JPN":"あらら？　ヘンタイですね。ずっと私をそんな目で見ていたんですか？","ENG":"Ooh, feisty much? Were you always looking at me with that in mind?","TWN":"喔～？還真是下流的想法，難道你一直都是這麼看待我的？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_QM","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그런데 어쩌나? 박사님은 제 취향이 아닌데?","JPN":"でもどうしよう？　博士は私のタイプじゃないんだよな～","ENG":"But boo hoo. You're not my type.","TWN":"但是抱歉喔？博士你不是我的菜欸？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_QM","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"LONE_EXILER_NPC_QM","text":{"KOREA":"으아아아!! 몇 번이나 말해!","JPN":"ぐおおお！！　何度話せばわかるんだ！","ENG":"AGHHHHH!! Hey, how many times do I have to tell you?!","TWN":"呃啊啊啊！！我還要說幾次你才明白！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_QM","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"LONE_EXILER_NPC_QM","text":{"KOREA":"내 이상형은 이지적이고 차분하면서 오직 나에게만 상냥한 미소를 보여주는 청초한 여성이야!","JPN":"僕のタイプは知的で落ち着いていて、僕だけに優しい笑顔を見せてくれる清楚な女性だ！","ENG":"I want an elegant woman who is intelligent, calm, and smiles only at me!","TWN":"我的菜是理智、沉穩，只會對我露出溫柔微笑的優雅女性！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_QM","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"LONE_EXILER_NPC_QM","text":{"KOREA":"너 같이 불여시 같은 여자는 관심 없다고!","JPN":"お前のような腹黒キツネみたいな女には興味ないんだよ！","ENG":"I'm not interested in vulpine women like you!","TWN":"我對你這種狐狸精一樣的女人一點興趣都沒有！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_QM","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아하하, 재밌어라! 역시 이세계 의뢰인님이랑 똑같아!","JPN":"アハハ、面白い！　やっぱり異世界の依頼人とそっくり！","ENG":"Ah hah hah, that's so funny! You're just like the otherworldly client I met!","TWN":"哈哈哈，真是有趣呀！果然和那個世界的委託人一模一樣！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_QM","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그보다 로널드 리 박사님?","JPN":"それよりロナルド・リー博士？","ENG":"Oh, but, Dr. Ronald Lee?","TWN":"那個，羅那魯多·李博士？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"박사님은 <color=#ffd34c>네피림 고치</color>에 볼 일이 있다고 하시지 않았나요?","JPN":"博士は<color=#ffd34c>ネフィリムの繭</color>に用があるとおっしゃっていませんでしたか？","ENG":"Didn't you say you had business to take care of regarding the <color=#ffd34c>Nephil cocoons</color>?","TWN":"你想要說的事情，是和<color=#ffd34c>諾菲力繭</color>有關嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"설마, 고치에 무슨 문제라도?","JPN":"まさか、繭に何か問題が？","ENG":"Wait, is there a problem with the cocoons?","TWN":"難道，是繭出了什麼問題？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"그래! 바로 그 설마라고! 소령!","JPN":"そうだ！　そのまさかだ！　少佐！","ENG":"Yes, that's exactly what I'm saying, Major!","TWN":"沒錯！就是那個！少校！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L44_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"아무튼 당장 따라와!","JPN":"とにかく今すぐについてきてくれ！","ENG":"Just, come follow me!","TWN":"快跟我來！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"어쩌면 국가 비상사태가 발생했을지도 모른단 말이야!","JPN":"もしかすると国家非常事態が起きるかもしれないんだ！","ENG":"This could turn out to be a national disaster!","TWN":"這可能是國家等級的緊急情況！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};